def dgd_update(M, key, target, dim, alpha, eta):
    activation = [0.0] * dim
    for i in range(dim):
        row = M[i]
        s = 0.0
        for j in range(dim):
            s += row[j] * key[j]
        activation[i] = s

    key_norm2 = 0.0
    for j in range(dim):
        v = key[j]
        key_norm2 += v * v

    if key_norm2 < 1e-12:
        if alpha != 1.0:
            for i in range(dim):
                row = M[i]
                for j in range(dim):
                    row[j] *= alpha
        return M

    inv_denom = 1.0 / (1e-12 + key_norm2)

    for i in range(dim):
        row = M[i]
        err = target[i] - activation[i]
        scale = eta * err * inv_denom
        if alpha == 1.0:
            for j in range(dim):
                row[j] += scale * key[j]
        else:
            for j in range(dim):
                row[j] = alpha * row[j] + scale * key[j]

    return M
